external_knowledge:
; Market capitalization is the total value of outstanding shares of a company's stock; 
; A market index is a hypothetical portfolio of investment holdings that represents a particular segment of the financial market; 
; The query assumes the existence of the following tables: index_components, stocks, index_data, transactions, and users, which are not shown in the query.

sql:
SELECT index_name
FROM market_indices
WHERE index_id = 0;

